//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "OPC relationships & part addressing: rId resolution, TargetMode
//! External, relative-reference resolution, .rels naming".
//!
//! Each `#[test]` encodes a Word-compliance constraint mined from the
//! OOXML / OPC specs. A FAILING assertion here is NOT a test bug to be made
//! green by weakening it: it encodes a real divergence between stemma and how
//! Microsoft Word consumes/repairs the package. When a test fails, classify the
//! gap (validator blind spot, resolution-branch hole, false positive) and fix
//! the engine at the source — never the assertion.
//!
//! Methodology note (consumption vs. save): stemma round-trips untouched content
//! byte-verbatim, so `reserialize()` of an unedited document reflects stemma's
//! verbatim-preservation contract, not Word's normalization. The specs in this
//! file are all `opensClean` validity checks against the public package
//! validator (`stemma::api::validate`), which is the correct surface for
//! "is this package well-formed / would Word repair it".

use std::io::{Read, Write};

use stemma::ExportOptions;
use stemma::api::{Document, validate};
use zip::write::FileOptions;

// ─── Prelude / plumbing ──────────────────────────────────────────────────────

/// Build a valid minimal `.docx` from a `document.xml` body fragment.
///
/// `body_xml` is wrapped in `<w:document ...><w:body>…</w:body></w:document>`.
/// `extra_parts` is a list of `(part_name, xml)` written verbatim into the zip;
/// for each one whose name we recognize (styles.xml, numbering.xml) a matching
/// `[Content_Types].xml` Override is added so the package stays content-typed.
///
/// `word/_rels/document.xml.rels` is intentionally EMPTY — the dangling-reference
/// specs need a part whose `.rels` provides no Relationship Ids, so any `r:id` /
/// `r:embed` / `r:link` in the body is unresolved.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for any recognized extra parts.
    let mut overrides = String::new();
    for (name, _) in extra_parts {
        let part_path = if name.starts_with('/') {
            name.to_string()
        } else {
            format!("/{name}")
        };
        if name.ends_with("styles.xml") {
            overrides.push_str(&format!(
                r#"<Override PartName="{part_path}" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"/>"#
            ));
        } else if name.ends_with("numbering.xml") {
            overrides.push_str(&format!(
                r#"<Override PartName="{part_path}" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"/>"#
            ));
        }
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    // Deliberately empty: no relationship Ids exist for the document part.
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (name, xml) in extra_parts {
            zip.start_file(*name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
#[allow(dead_code)]
fn document_xml_of(docx: &[u8]) -> String {
    let mut archive = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = archive
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse -> serialize -> return the re-emitted `word/document.xml`.
#[allow(dead_code)]
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Render a `ValidationReport` for assertion messages without depending on its
/// Display impl (it derives only Debug).
fn report_summary(bytes: &[u8]) -> String {
    let report = validate(bytes);
    format!("{report:?}")
}

/// True iff the public package validator reports the package clean.
fn opens_clean(bytes: &[u8]) -> bool {
    validate(bytes).ok
}

// ─── Specs ───────────────────────────────────────────────────────────────────

/// I-REL-001: an r:embed on a:blip naming no relationship Id is dangling.
/// ECMA-376 Part 2 OPC §6.5; ISO 29500-1 §9.2.
#[test]
fn dangling_rembed_blip_flagged() {
    let body = r#"<w:p><w:r><w:drawing><wp:inline xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing"><wp:extent cx="914400" cy="914400"/><wp:docPr id="1" name="Picture 1"/><a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:blipFill><a:blip xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" r:embed="rId999"/><a:stretch><a:fillRect/></a:stretch></pic:blipFill></pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        !opens_clean(&b),
        "An r:embed on a DrawingML a:blip is an explicit relationship reference; \
r:embed=\"rId999\" names no Relationship Id in word/_rels/document.xml.rels, so it is a \
dangling reference and must be flagged I-REL-001 (Error). Word repairs the file and drops the \
picture. [ECMA-376 Part 2 OPC §6.5; ISO 29500-1 §9.2; I-REL-001] report={}",
        report_summary(&b)
    );
}

/// I-REL-001: an r:link on a:blip (linked image) naming no relationship Id is
/// dangling, independent of the would-be TargetMode=External.
/// ECMA-376 Part 2 OPC §6.5; ISO 29500-1 §9.2.
#[test]
fn dangling_rlink_blip_flagged() {
    let body = r#"<w:p><w:r><w:drawing><wp:inline xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing"><wp:extent cx="914400" cy="914400"/><wp:docPr id="1" name="Picture 1"/><a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:blipFill><a:blip xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" r:link="rId888"/><a:stretch><a:fillRect/></a:stretch></pic:blipFill></pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        !opens_clean(&b),
        "An r:link on a DrawingML a:blip (a linked image) is an explicit relationship reference; \
r:link=\"rId888\" resolves to no Relationship Id, so I-REL-001 must fire. Reference resolution is \
required even for External-target linked images (External-ness only suppresses the in-package \
target check I-REL-003, not I-REL-001). [ECMA-376 Part 2 OPC §6.5; ISO 29500-1 §9.2; I-REL-001] \
report={}",
        report_summary(&b)
    );
}

/// Negative boundary: empty r:embed/r:link name no relationship and must NOT be
/// treated as dangling. ECMA-376 Part 2 OPC §6.5; ISO 29500-1 §9.2.
#[test]
fn empty_rembed_rlink_not_dangling() {
    let body = r#"<w:p><w:r><w:drawing><wp:inline xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing"><wp:extent cx="914400" cy="914400"/><wp:docPr id="1" name="Picture 1"/><a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:blipFill><a:blip xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" r:embed="" r:link=""/><a:stretch><a:fillRect/></a:stretch></pic:blipFill></pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        opens_clean(&b),
        "Both r:embed and r:link are empty and reference nothing; no relationship lookup is \
performed, so I-REL-001 must NOT fire and the package must validate clean. Word writes an empty \
sibling alongside a live reference in conformant markup, so flagging an empty reference is a false \
positive. [ECMA-376 Part 2 OPC §6.5; ISO 29500-1 §9.2] report={}",
        report_summary(&b)
    );
}

/// A w:hyperlink whose r:id names no relationship is a dangling explicit
/// reference; the public package validator must report NOT clean.
/// ECMA-376 Part 2 OPC §6.5.2/§6.5.3; ISO 29500-1 §9.2, §17.16.22.
#[test]
fn dangling_hyperlink_rid_must_not_open_clean() {
    let body = r#"<w:p><w:hyperlink r:id="rId88" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><w:r><w:t>click me</w:t></w:r></w:hyperlink></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        !opens_clean(&b),
        "The hyperlink's r:id=\"rId88\" has no matching Relationship in document.xml.rels (empty), \
so the explicit reference is dangling. §17.16.22 + §9.2 require it to resolve; an unresolvable \
explicit reference is a repair-class defect in Word, so the package validator must NOT report it \
clean. [ECMA-376 Part 2 OPC §6.5.2/§6.5.3; ISO 29500-1 §9.2, §17.16.22] report={}",
        report_summary(&b)
    );
}

/// A picture whose a:blip r:embed names no relationship is a dangling image
/// reference; the package validator must report NOT clean.
/// ECMA-376 Part 2 OPC §6.5.2/§6.5.3; ISO 29500-1 §9.2, §17.3.3.9.
#[test]
fn dangling_blip_embed_must_not_open_clean() {
    let body = r#"<w:p><w:r><w:drawing><wp:inline xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing"><wp:extent cx="100" cy="100"/><a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:blipFill><a:blip r:embed="rId99" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"/></pic:blipFill></pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        !opens_clean(&b),
        "a:blip r:embed=\"rId99\" has no Relationship in the (empty) document.xml.rels, so the \
image reference is dangling. §9.2 requires the explicit reference to resolve; an unresolvable \
image embed is data loss that Word repairs, so the validator must NOT report the package clean. \
[ECMA-376 Part 2 OPC §6.5.2/§6.5.3; ISO 29500-1 §9.2, §17.3.3.9] report={}",
        report_summary(&b)
    );
}

/// Full pic:pic with a dangling r:embed: validate must flag I-REL-001 and not
/// silently drop. ECMA-376 Part 2 OPC §6.5.3; ISO 29500-1 §9.2, §J.5.
#[test]
fn dangling_blip_embed_flagged_no_silent_drop() {
    let body = r#"<w:p><w:r><w:drawing><wp:inline xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing"><wp:extent cx="914400" cy="914400"/><wp:docPr id="1" name="Picture 1"/><a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:nvPicPr><pic:cNvPr id="1" name="Picture 1"/><pic:cNvPicPr/></pic:nvPicPr><pic:blipFill><a:blip r:embed="rIdMissing" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"/><a:stretch><a:fillRect/></a:stretch></pic:blipFill><pic:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="914400" cy="914400"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom></pic:spPr></pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        !opens_clean(&b),
        "r:embed=\"rIdMissing\" has no backing relationship in the (empty) document.xml.rels, so \
I-REL-001 must fire and opensClean must be false; Word would flag this file for repair (data-loss) \
rather than open it cleanly. [ECMA-376 Part 2 OPC §6.5.3; ISO 29500-1 §9.2, §J.5] report={}",
        report_summary(&b)
    );
}

/// Full pic:pic with a dangling r:link (linked image): validate must flag
/// I-REL-001. ECMA-376 Part 2 OPC §6.5.3; ISO 29500-1 §9.2.
#[test]
fn dangling_blip_link_flagged_no_silent_drop() {
    let body = r#"<w:p><w:r><w:drawing><wp:inline xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing"><wp:extent cx="914400" cy="914400"/><wp:docPr id="2" name="Picture 2"/><a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:nvPicPr><pic:cNvPr id="2" name="Picture 2"/><pic:cNvPicPr/></pic:nvPicPr><pic:blipFill><a:blip r:link="rIdLinkMissing" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"/><a:stretch><a:fillRect/></a:stretch></pic:blipFill><pic:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="914400" cy="914400"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom></pic:spPr></pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        !opens_clean(&b),
        "r:link=\"rIdLinkMissing\" has no backing relationship, so the linked image cannot \
resolve; I-REL-001 must fire and opensClean must be false. Word cannot resolve the linked image \
and reports the file as needing repair. [ECMA-376 Part 2 OPC §6.5.3; ISO 29500-1 §9.2] report={}",
        report_summary(&b)
    );
}

/// A w:headerReference whose r:id names no relationship is a dangling reference
