#[test]
fn dangling_header_reference_rid_flagged() {
    let body = r#"<w:p><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr><w:headerReference w:type="default" r:id="rIdHdrMissing" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"/></w:sectPr>"#;
    let b = make_docx(body, &[]);
    assert!(
        !opens_clean(&b),
        "headerReference r:id=\"rIdHdrMissing\" has no backing relationship in the empty \
document.xml.rels, so the header part cannot be located; I-REL-001 must fire and opensClean must \
be false. Word cannot resolve the section header and reports the file as needing repair. \
[ISO 29500-1 §17.10.5, §9.2; ECMA-376 Part 2 OPC §6.5] report={}",
        report_summary(&b)
    );
}

/// A DrawingML a:hlinkClick whose r:id names no relationship is a dangling
/// reference. ISO 29500-1 §9.2, §J.5; ECMA-376 Part 2 OPC §6.5.
#[test]
fn dangling_drawingml_hlinkclick_rid_flagged() {
    let body = r#"<w:p><w:r><w:drawing><wp:inline xmlns:wp="http://schemas.openxmlformats.org/drawingml/2006/wordprocessingDrawing"><wp:extent cx="914400" cy="914400"/><wp:docPr id="3" name="Shape 3"><a:hlinkClick r:id="rIdLinkMissing" xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"/></wp:docPr><a:graphic xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main"><a:graphicData uri="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:pic xmlns:pic="http://schemas.openxmlformats.org/drawingml/2006/picture"><pic:nvPicPr><pic:cNvPr id="3" name="Shape 3"/><pic:cNvPicPr/></pic:nvPicPr><pic:blipFill><a:blip r:embed="rId1" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"/><a:stretch><a:fillRect/></a:stretch></pic:blipFill><pic:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="914400" cy="914400"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom></pic:spPr></pic:pic></a:graphicData></a:graphic></wp:inline></w:drawing></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        !opens_clean(&b),
        "a:hlinkClick r:id=\"rIdLinkMissing\" (and the blip r:embed=\"rId1\") have no backing \
relationships in the empty document.xml.rels, so at least one dangling explicit reference exists; \
I-REL-001 must fire and opensClean must be false. [ISO 29500-1 §9.2, §J.5; ECMA-376 Part 2 OPC \
§6.5] report={}",
        report_summary(&b)
    );
}

/// Internal Targets in the package-rels part /_rels/.rels resolve against the
/// package root, so Target="word/document.xml" resolves and the package opens
/// clean. ISO 29500-2 OPC §6.5.2, §6.4.2; I-REL-003; I-PKG-001.
#[test]
fn package_rels_internal_target_resolves_from_package_root() {
    let body = r#"<w:p><w:r><w:t>Minimal package reachable through /_rels/.rels.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        opens_clean(&b),
        "Per OPC §6.5.2, the package-rels Target=\"word/document.xml\" resolves against the \
package root to the present main-document part; no I-REL-003 (unresolved target) and no I-PKG-001 \
(missing package-rels) must fire, so the package must open clean. A failure here means stemma \
mis-resolves package-root relationships. [ISO 29500-2 OPC §6.5.2, §6.4.2; I-REL-003; I-PKG-001] \
report={}",
        report_summary(&b)
    );
}

/// A Relationships part is exempt from per-part content-type requirements and is
/// never a relationship source/target; a package whose only auxiliary parts are
/// _rels parts opens clean. ISO 29500-2 OPC §6.5.2, §6.5.3; I-CT-001/I-CT-002.
#[test]
fn relationships_part_is_not_content_typed_and_has_no_rels_to_itself() {
    let body = r#"<w:p><w:r><w:t>Document whose only auxiliary parts are _rels parts.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert!(
        opens_clean(&b),
        "Per OPC §6.5.2/§6.5.3, the _rels parts require neither a content-type Override nor an \
inbound relationship; the validator must not raise I-CT-001/I-CT-002 against them nor an \
orphan-part/I-STORY finding, so the package must open clean. [ISO 29500-2 OPC §6.5.2, §6.5.3; \
I-CT-001/I-CT-002] report={}",
        report_summary(&b)
    );
}

